import face_recognition
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)

# Function to encode faces
def encode_faces(directory):
    encodings = []
    images = os.listdir(directory)
    for image in images:
        image_path = os.path.join(directory, image)
        encoding = face_recognition.face_encodings(face_recognition.load_image_file(image_path))[0]
        encodings.append(encoding)
    return encodings

# Function to train model
def train_model(encodings):
    return {
        "Employee1": encodings[0],
        "Employee2": encodings[1],
        "Employee3": encodings[2]
    }

# Load pre-trained model
model = face_recognition.face_encodings(face_recognition.load_image_file('known_faces.jpg'))

# API endpoint to train model and get confidence scores
@app.route('/train', methods=['POST'])
def train():
    if 'files' in request.files:
        files = request.files['files']
        for file in files:
            filename = secure_filename(file.filename)
            file.save(os.path.join('images', filename))
        encodings = encode_faces('images')
        model = train_model(encodings)
        return jsonify(model), 200
    else:
        return jsonify({"error": "No files uploaded"}), 400

